INSERT INTO `cookies_policies` (`id`, `name`, `content`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`) VALUES
(1, 'Cookie Policy', '<p><strong>Last Updated: May 2026</strong></p><p style=\"text-align: justify;\">This Cookie Policy explains how Garuda Technologies (&#039;we&#039;, &#039;us&#039;, or &#039;our&#039;) uses cookies and similar tracking technologies on <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"http://garudatechnologies.co.in\"><strong>garudatechnologies.co.in</strong></a> (the &#039;Website&#039;). By continuing to use the Website, you consent to our use of cookies as described in this policy. This policy should be read alongside our Privacy Policy.</p><h3>What Are Cookies?</h3><p style=\"text-align: justify;\">Cookies are small text files placed on your device (computer, smartphone, or tablet) by websites you visit. They are widely used to make websites function efficiently and to provide information to the website owner. Cookies do not contain personally identifiable information on their own, but they can be linked to personal data we hold about you when used in combination with other information.</p><h3>Types of Cookies We Use</h3><table><tbody><tr><td rowspan=\"1\" colspan=\"1\"><p><strong>Cookie Type</strong></p></td><td rowspan=\"1\" colspan=\"1\"><p><strong>Purpose and Data Collected</strong></p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Strictly Necessary Cookies</p></td><td rowspan=\"1\" colspan=\"1\"><p>Required for the website to function. These enable core features like page navigation, security, and form submission. They cannot be disabled without affecting website functionality. No personal data collected for marketing purposes.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Performance and Analytics Cookies</p></td><td rowspan=\"1\" colspan=\"1\"><p>Collect anonymized data about how visitors use the website — pages visited, time spent, error pages encountered. We use Google Analytics for this purpose. This data helps us improve website performance and content.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Functionality Cookies</p></td><td rowspan=\"1\" colspan=\"1\"><p>Remember your preferences and settings (language, region, display options) to provide a more personalized experience on return visits. Do not track browsing activity across other websites.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Marketing and Targeting Cookies</p></td><td rowspan=\"1\" colspan=\"1\"><p>Used to deliver advertisements relevant to your interests. May be set by advertising partners including Google Ads. These cookies track browsing activity across websites to build interest profiles. You may opt out through your browser settings.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Travel Booking Cookies</p></td><td rowspan=\"1\" colspan=\"1\"><p>Session cookies used during the travel booking process to maintain your booking progress, selected options, and quote data within a single session. These are deleted when you close your browser.</p></td></tr></tbody></table><p></p><h3>Third-Party Cookies</h3><p style=\"text-align: justify;\">Some cookies on our website are set by third-party services. These include Google Analytics (performance measurement), Google Ads (advertising), LinkedIn Insight Tag (B2B advertising), and embedding tools for maps and travel booking widgets. Each third party&#039;s cookie policy governs its use of data collected through those cookies.</p><h3>How Long Do Cookies Last?</h3><table><tbody><tr><td rowspan=\"1\" colspan=\"1\"><p><strong>Cookie Duration</strong></p></td><td rowspan=\"1\" colspan=\"1\"><p><strong>Details</strong></p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Session cookies</p></td><td rowspan=\"1\" colspan=\"1\"><p>Deleted when you close your browser. Used for active browsing and booking sessions.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Persistent cookies</p></td><td rowspan=\"1\" colspan=\"1\"><p>Remain on your device for a defined period (typically 30 days to 2 years, depending on the cookie). Used for preference settings and analytics.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Google Analytics cookies</p></td><td rowspan=\"1\" colspan=\"1\"><p>Standard retention period of 26 months unless you opt out.</p></td></tr></tbody></table><p></p><h3>Managing Your Cookie Preferences</h3><p style=\"text-align: justify;\">You can control and manage cookies in several ways:</p><p>• Browser settings: Most browsers allow you to refuse cookies, delete existing cookies, and set preferences for specific websites. Refer to your browser&#039;s help documentation for instructions.<br>• Google Analytics opt-out: Install the Google Analytics Opt-out Browser Add-on available at tools.google.com/dlpage/gaoptout<br>• Google Ads: Manage ad personalization at <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"http://adssettings.google.com\"><strong>adssettings.google.com</strong></a><br>• Cookie consent banner: When you first visit the website, a cookie consent banner allows you to accept or decline non-essential cookie categories.</p><p style=\"text-align: justify;\">Disabling certain cookies may affect the functionality of the website, including the travel booking process and personalized content display.</p><h3>Your Rights Under Indian Data Protection Law</h3><p style=\"text-align: justify;\">India&#039;s Digital Personal Data Protection Act (DPDPA) 2023 grants users rights over their personal data. To the extent cookies collect personal data, you have the right to access, correct, and withdraw consent for processing of your personal data. To exercise these rights, contact us at <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"mailto:info@garudatechnologies.co.in\"><strong>info@garudatechnologies.co.in</strong></a><strong>.</strong></p><h3>Changes to This Cookie Policy</h3><p style=\"text-align: justify;\">We may update this Cookie Policy from time to time to reflect changes in technology, regulation, or our business practices. The &#039;Last Updated&#039; date at the top of this page indicates when the policy was last revised. Continued use of the website after updates constitutes acceptance of the revised policy.</p><h2>Contact</h2><p style=\"text-align: justify;\">For questions about this Cookie Policy or our use of cookies, contact: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"mailto:info@garudatechnologies.co.in\"><strong>info@garudatechnologies.co.in</strong></a> | <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"tel:+919910844235\"><strong>+91-9910844235</strong></a> |<strong> Plot No. 750, Udyog Vihar Phase V Rd, Phase V, Udyog Vihar, Sector 19, Gurugram, Haryana 122016.</strong></p><h3></h3>', 'Cookie Policy | Garuda Technologies Gurgaon', 'Garuda Technologies cookie policy. Learn how we use cookies on garudatechnologies.co.in, what types we use, how to manage them, and your rights under India\'s data protection rules.', '[\"Garuda Technologies cookie policy\",\"cookies IT company India\",\"website cookie policy Gurgaon\",\"DPDP cookie India\"]', '2026-04-18 12:17:53', '2026-05-18 13:01:02');

