INSERT INTO `disclaimers` (`id`, `name`, `content`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`) VALUES
(1, 'Disclaimer', '<p><strong>Last Updated: May 2026</strong></p><p style=\"text-align: justify;\">The information provided on this website — <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"http://garudatechnologies.co.in\"><strong>garudatechnologies.co.in</strong></a> — is for general informational purposes only. Garuda Technologies makes every reasonable effort to keep the information current and accurate, but makes no representations or warranties of any kind, express or implied, about the completeness, accuracy, reliability, suitability, or availability of the information, products, services, or related graphics contained on the website.</p><h3>No Professional Advice</h3><p style=\"text-align: justify;\">The content on this website does not constitute professional IT consulting, legal, financial, medical, or travel advice. Any reliance you place on information from this website is strictly at your own risk. For professional advice specific to your business or personal situation, contact Garuda Technologies directly at <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"mailto:info@garudatechnologies.co.in\"><strong>info@garudatechnologies.co.in</strong></a> or<a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"tel:9910844235\"> </a><a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"tel:+919910844235\"><strong>+91-9910844235</strong></a>.</p><h3>Service Availability</h3><p style=\"text-align: justify;\">Garuda Technologies reserves the right to modify, suspend, or discontinue any service, product, or feature described on this website at any time without prior notice. Pricing, availability, and service specifications are subject to change. Current pricing and availability are confirmed at the time of inquiry and formal engagement.</p><h3>Travel Services Disclaimer</h3><p style=\"text-align: justify;\">Travel prices, flight fares, hotel rates, and cruise prices listed or quoted are indicative and subject to availability at the time of booking confirmation. Garuda Technologies acts as a travel booking intermediary and is not the airline, hotel, cruise line, or car rental operator. The terms and conditions of the respective service provider govern each booking. Garuda Technologies is not liable for delays, cancellations, overbookings, or service quality issues that are the direct responsibility of the travel service provider.</p><p style=\"text-align: justify;\">Visa requirements, travel advisories, and entry conditions vary by destination country and are the sole responsibility of the traveler to verify. Garuda Technologies provides general travel information only and does not provide legal immigration or visa advice.</p><h3>External Links</h3><p style=\"text-align: justify;\">This website may contain links to external websites operated by third parties, including the seven Garuda Technologies travel brands (Globalairhub, Zippoair, Tripsomaker, Airoflighticket, Airotrolly, Businessclassflyts, and Globalairticketing). These links are provided for convenience only. Garuda Technologies has no control over the content of those websites and accepts no responsibility for them or for any loss or damage that may arise from your use of them.</p><h3>Intellectual Property</h3><p style=\"text-align: justify;\">All content on this website — including text, graphics, logos, images, and software — is the property of Garuda Technologies or its content suppliers and is protected under applicable Indian intellectual property laws. Unauthorized reproduction, distribution, or modification of any content from this website is prohibited without prior written permission from Garuda Technologies.</p><h3>Limitation of Liability</h3><p style=\"text-align: justify;\">To the maximum extent permitted by applicable law, Garuda Technologies shall not be liable for any indirect, incidental, special, consequential, or punitive damages arising from your use of or inability to use this website or any services described on it. Garuda Technologies&#039; total liability for any claim arising from use of this website shall not exceed the amount paid by you to Garuda Technologies in the three months preceding the claim.</p><h3>Governing Law</h3><p style=\"text-align: justify;\">This disclaimer is governed by and construed in accordance with the laws of India. Any disputes arising in connection with this disclaimer or the use of this website are subject to the exclusive jurisdiction of the courts of Gurugram, Haryana, India.</p><h3>Contact for Disclaimer Queries</h3><p style=\"text-align: justify;\">For questions about this disclaimer, contact Garuda Technologies at <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"mailto:info@garudatechnologies.co.in\"><strong>info@garudatechnologies.co.in</strong></a> or <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"tel:+919910844235\"><strong>+91-9910844235</strong></a>. The mailing address is: <strong>Plot No. 750, Udyog Vihar Phase V Rd, Phase V, Udyog Vihar, Sector 19, Gurugram, Haryana 122016.</strong></p>', 'Disclaimer | Garuda Technologies Gurgaon', 'Read the Garuda Technologies disclaimer. Information on this website is for general purposes only. Garuda Technologies makes no warranties about completeness or accuracy of content.', '[\"Garuda Technologies disclaimer\",\"IT company disclaimer Gurgaon\",\"website disclaimer India\",\"garuda technologies legal\"]', '2026-04-18 16:58:10', '2026-05-18 12:41:00');

