INSERT INTO `privacy_policies` (`id`, `name`, `content`, `meta_title`, `meta_description`, `meta_keywords`, `created_at`, `updated_at`) VALUES
(1, 'Privacy Policy', '<p><strong>Last Updated: May 2026</strong></p><p style=\"text-align: justify;\">Garuda Technologies (&#039;we&#039;, &#039;us&#039;, or &#039;our&#039;) is committed to protecting your personal data. This Privacy Policy explains how we collect, use, store, share, and protect information about you when you visit <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"http://garudatechnologies.co.in\"><strong>garudatechnologies.co.in</strong></a>, use our IT and digital services, or make travel bookings through our travel brands. This policy is compliant with India&#039;s Digital Personal Data Protection Act (DPDPA) 2023.</p><h3>Information We Collect</h3><table><tbody><tr><td rowspan=\"1\" colspan=\"1\"><p><strong>Data Type</strong></p></td><td rowspan=\"1\" colspan=\"1\"><p><strong>What We Collect and When</strong></p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Contact information</p></td><td rowspan=\"1\" colspan=\"1\"><p>Name, phone number, email address, and company name provided when you contact us, submit a form, or request a quote.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Booking information</p></td><td rowspan=\"1\" colspan=\"1\"><p>For travel bookings: passenger names, travel dates, passport details (where required by airline/visa), and payment information.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>IT project information</p></td><td rowspan=\"1\" colspan=\"1\"><p>Website URL, business details, and project requirements shared during IT service consultations.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Usage data</p></td><td rowspan=\"1\" colspan=\"1\"><p>IP address, browser type, pages visited, time on site, and referring URL collected automatically via cookies and analytics tools.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Communication data</p></td><td rowspan=\"1\" colspan=\"1\"><p>Emails, chat messages, and call notes from interactions with the Garuda Technologies team.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Payment data</p></td><td rowspan=\"1\" colspan=\"1\"><p>We do not store full payment card details. Payment processing is handled by certified payment gateways. We retain transaction reference numbers and amounts for billing records.</p></td></tr></tbody></table><h3>How We Use Your Information</h3><table><tbody><tr><td rowspan=\"1\" colspan=\"1\"><p><strong>Purpose</strong></p></td><td rowspan=\"1\" colspan=\"1\"><p><strong>How Your Data Is Used</strong></p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Service delivery</p></td><td rowspan=\"1\" colspan=\"1\"><p>Processing IT project requirements, delivering completed services, and managing travel bookings on your behalf.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Communication</p></td><td rowspan=\"1\" colspan=\"1\"><p>Responding to inquiries, sending project updates, booking confirmations, and service-related notifications.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Billing and accounts</p></td><td rowspan=\"1\" colspan=\"1\"><p>Generating invoices, processing payments, and maintaining financial records as required by Indian accounting law.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Website improvement</p></td><td rowspan=\"1\" colspan=\"1\"><p>Analyzing usage data to improve website content, performance, and user experience.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Marketing (with consent)</p></td><td rowspan=\"1\" colspan=\"1\"><p>Sending information about new services, offers, and industry insights where you have provided explicit consent. You may withdraw consent at any time.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Legal compliance</p></td><td rowspan=\"1\" colspan=\"1\"><p>Retaining records as required by Indian law, including GST records for 7 years and travel booking records for the duration required by applicable regulations.</p></td></tr></tbody></table><h3>Legal Basis for Processing</h3><p style=\"text-align: justify;\">We process your personal data on the following legal bases under the DPDPA 2023: your consent (for marketing communications and non-essential cookies), the performance of a contract (for service delivery and travel bookings), compliance with legal obligations (for tax and regulatory record-keeping), and legitimate interests (for website analytics and security monitoring).</p><h3>Data Sharing</h3><p style=\"text-align: justify;\">Garuda Technologies does not sell your personal data to third parties. We share your data only in the following circumstances:<br>• Travel service providers: Airlines, hotels, cruise lines, and car rental operators require booking information (passenger names, travel dates, contact details) to confirm reservations.<br>• Payment processors: Transaction data is shared with certified payment gateway providers to process payments securely.<br>• Technology partners: IT service delivery may involve subcontractors or cloud service providers (AWS, Google Cloud, Microsoft Azure) who process data on our behalf under data processing agreements.<br>• Legal authorities: We disclose data to law enforcement or regulatory authorities when required by applicable Indian law or court order.</p><h3>Data Retention</h3><table><tbody><tr><td rowspan=\"1\" colspan=\"1\"><p><strong>Data Category</strong></p></td><td rowspan=\"1\" colspan=\"1\"><p><strong>Retention Period</strong></p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>IT project data</p></td><td rowspan=\"1\" colspan=\"1\"><p>Retained for the duration of the engagement plus 3 years for reference and support purposes.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Travel booking data</p></td><td rowspan=\"1\" colspan=\"1\"><p>Retained for 7 years from the booking date for GST and financial compliance purposes.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Marketing preferences</p></td><td rowspan=\"1\" colspan=\"1\"><p>Retained until you withdraw consent. Withdrawal requests processed within 30 days.</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Website analytics</p></td><td rowspan=\"1\" colspan=\"1\"><p>Anonymized aggregate data retained indefinitely. Individual session data retained for 26 months (Google Analytics standard).</p></td></tr><tr><td rowspan=\"1\" colspan=\"1\"><p>Communication records</p></td><td rowspan=\"1\" colspan=\"1\"><p>Email and call records retained for 2 years from last interaction.</p></td></tr></tbody></table><h3>Your Rights Under DPDPA 2023</h3><p>• Right to access: Request a copy of the personal data we hold about you.<br>• Right to correction: Request correction of inaccurate or incomplete personal data.<br>• Right to erasure: Request deletion of your personal data where it is no longer necessary for the purposes collected.<br>• Right to withdraw consent: Withdraw consent for marketing communications at any time without affecting processing based on other legal grounds.<br>• Right to grievance redressal: Raise concerns with our Data Protection Officer at <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"mailto:info@garudatechnologies.co.in\"><strong>info@garudatechnologies.co.in</strong></a><strong>.</strong></p><p style=\"text-align: justify;\">Requests under these rights will be processed within 30 days of receipt. Identity verification may be required before processing access or erasure requests.</p><h3>Data Security</h3><p style=\"text-align: justify;\">Garuda Technologies implements appropriate technical and organizational security measures to protect your personal data against unauthorized access, alteration, disclosure, or destruction. These measures include SSL/TLS encryption for data in transit, access controls limiting data access to authorized personnel, regular security audits of systems handling personal data, and secure deletion procedures for data no longer required.</p><h3>International Data Transfers</h3><p style=\"text-align: justify;\">Travel booking data may be transferred to airlines, hotels, and travel service providers operating outside India when you book international travel. Such transfers occur because they are necessary to perform the travel booking contract. We ensure that international service providers maintain appropriate data protection standards.</p><h3>Children&#039;s Privacy</h3><p style=\"text-align: justify;\">Garuda Technologies does not knowingly collect personal data from children under the age of 18 without verified parental consent. If you believe we have inadvertently collected data from a minor, contact us immediately at <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"mailto:info@garudatechnologies.co.in\"><strong>info@garudatechnologies.co.in</strong></a> and we will delete the data promptly.</p><h3>Contact — Privacy Queries</h3><p style=\"text-align: justify;\">For privacy-related questions, data subject requests, or concerns: Data Protection Contact: Garuda Technologies | Email: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"mailto:info@garudatechnologies.co.in\"><strong>info@garudatechnologies.co.in</strong></a> | Phone: <a target=\"_blank\" rel=\"noopener noreferrer nofollow\" href=\"tel:+919910844235\"><strong>+91-9910844235</strong></a> | Address: <strong>Plot No. 750, Udyog Vihar Phase V Rd, Phase V, Udyog Vihar, Sector 19, Gurugram, Haryana 122016.</strong></p>', 'Privacy Policy | Garuda Technologies Gurgaon', 'Garuda Technologies privacy policy. How we collect, use, store, and protect your personal data. Compliant with India\'s DPDPA 2023. Contact us at info@garudatechnologies.co.in.', '[\"Garuda Technologies privacy policy\",\"IT company privacy policy India\",\"DPDPA compliance Gurgaon\",\"data protection IT company\",\"privacy policy travel company India\"]', '2026-04-18 13:35:30', '2026-05-18 13:09:20');

